                    // Check if a resize/re-center is needed, with a small tolerance
                    if (Math.abs(win.width - targetWidth) > 1 || Math.abs(win.height - targetHeight) > 1 || Math.abs(win.x - targetX) > 1 || Math.abs(win.y - targetY) > 1) {
