// --- Constants & Types ---
const MAX_HABITS = 10;

interface HabitLog {
    [date: string]: boolean[]; // 'YYYY-MM-DD': [true, false, ...]
}

interface HabitTrackerProps {
    user: User;
    onClose?: () => void;
}

const DEFAULT_HABITS = [
    "Wake up by 6 AM",
    "Exercise / Workout",
    "Read 10 pages",
    "Deep Work (2 hrs)",
    "Drink 3L Water",
    "Meditate (10 mins)",
    "No Sugar",
    "Review Goals",
    "Code / Skill Practice",
    "Sleep by 11 PM"
];

// Helper to calculate color based on score
const getScoreColor = (count: number) => {
    if (count === 10) return 'bg-green-500 border-green-600';
    if (count >= 6) return 'bg-blue-500 border-blue-600';
    if (count >= 3) return 'bg-orange-500 border-orange-600';
    return 'bg-red-500 border-red-600';
};

const getScoreTextColor = (count: number) => {
    if (count === 10) return 'text-green-500';
    if (count >= 6) return 'text-blue-500';
    if (count >= 3) return 'text-orange-500';
    return 'text-red-500';
};

