                        <div className="flex items-center gap-2">
                             <div className={`text-2xl font-bold ${getScoreTextColor(completedCount)}`}>{completedCount}</div>
                             <span className="text-sm text-slate-500 dark:text-slate-400 font-medium">/ {MAX_HABITS} Completed</span>
                        </div>
                        {isPerfect && (
                            <span className="px-3 py-1 bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 text-xs font-bold uppercase rounded-full animate-pulse">
                                Perfect Day
                            </span>
                        )}
                     </div>

                     <div className="w-full h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden mb-6">
                         <div 
                            className={`h-full transition-all duration-500 ease-out ${getScoreColor(completedCount).split(' ')[0]}`}
                            style={{ width: `${(completedCount / MAX_HABITS) * 100}%` }}
                         />
                     </div>

                     <div className="space-y-3">
                         {habits.map((habit, index) => (
                             <label 
                                key={index} 
                                className={`flex items-center p-3 rounded-xl border transition-all cursor-pointer group ${
                                    checks[index] 
                                    ? 'bg-slate-50 dark:bg-slate-800/50 border-slate-200 dark:border-slate-700' 
                                    : 'bg-white dark:bg-slate-900 border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-slate-600'
                                }`}
                             >
                                 <div className={`w-5 h-5 rounded-md border flex items-center justify-center transition-colors mr-3 ${
                                     checks[index]
                                     ? 'bg-indigo-500 border-indigo-500 text-white'
                                     : 'bg-transparent border-slate-300 dark:border-slate-600 group-hover:border-indigo-400'
                                 }`}>
                                     {checks[index] && <CheckIcon className="w-3.5 h-3.5 stroke-[3]" />}
                                 </div>
                                 <input 
                                    type="checkbox" 
                                    className="hidden" 
                                    checked={checks[index]} 
                                    onChange={() => onToggle(index)} 
                                 />
                                 <span className={`text-sm font-medium transition-all ${
                                     checks[index] 
                                     ? 'text-slate-400 dark:text-slate-500 line-through' 
                                     : 'text-slate-700 dark:text-slate-200'
                                 }`}>
                                     {habit}
                                 </span>
                             </label>
                         ))}
                     </div>
                </div>

                <div className="p-4 bg-slate-50 dark:bg-slate-800/50 text-center border-t border-slate-100 dark:border-slate-700">
                    <button onClick={onClose} className="px-6 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-lg transition-colors shadow-lg hover:shadow-indigo-500/25">
                        Done
                    </button>
                </div>
            </div>
        </div>
    );
};

const StatCard: React.FC<{ label: string; value: string | number; icon: React.ReactNode; color: string }> = ({ label, value, icon, color }) => (
    <div className="bg-white dark:bg-slate-800 p-5 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm flex items-center gap-4">
        <div className={`p-3 rounded-xl ${color} bg-opacity-10 text-${color.split('-')[1]}-600 dark:text-${color.split('-')[1]}-400`}>
            {icon}
        </div>
        <div>
            <p className="text-2xl font-bold text-slate-900 dark:text-white">{value}</p>
            <p className="text-xs font-bold uppercase tracking-wider text-slate-400 dark:text-slate-500">{label}</p>
        </div>
    </div>
);

// --- Main Page ---

const HabitTrackerPage: React.FC<HabitTrackerProps> = ({ user, onClose }) => {
    const [view, setView] = useState<'dashboard' | 'calendar' | 'reports' | 'settings'>('dashboard');
    const [habitNames, setHabitNames] = useLocalStorage<string[]>(`habit-names-${user.id}`, DEFAULT_HABITS);
    const [logs, setLogs] = useLocalStorage<HabitLog>(`habit-logs-${user.id}`, {});
    const [selectedDate, setSelectedDate] = useState<string | null>(null);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

    // Calendar View State
    const [currentMonth, setCurrentMonth] = useState(new Date());

    const today = format(new Date(), 'yyyy-MM-dd');

    // Calculated Stats
    const stats = useMemo(() => {
        const entries = Object.entries(logs);
        const totalLoggedDays = entries.length;
        const totalHabitsCompleted = entries.reduce((acc, [_, checks]) => acc + checks.filter(Boolean).length, 0);
        const perfectDays = entries.filter(([_, checks]) => checks.filter(Boolean).length === MAX_HABITS).length;

        // Simple streak calc (consecutive days with at least 1 habit)
        let streak = 0;
        const sortedDates = Object.keys(logs).sort().reverse();
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yesterdayStr = format(yesterday, 'yyyy-MM-dd');

        // Check today or yesterday to maintain streak
        let checkDate = new Date();
        // If no log today, streak relies on yesterday
        if (!logs[today]) {
             checkDate.setDate(checkDate.getDate() - 1);
        }

        while (true) {
            const dStr = format(checkDate, 'yyyy-MM-dd');
            if (logs[dStr] && logs[dStr].some(Boolean)) {
                streak++;
                checkDate.setDate(checkDate.getDate() - 1);
            } else {
                break;
            }
        }

        return { totalLoggedDays, totalHabitsCompleted, perfectDays, streak };
    }, [logs, today]);

    const handleToggleHabit = (date: string, index: number) => {
        setLogs(prev => {
            const dayLogs = prev[date] ? [...prev[date]] : Array(MAX_HABITS).fill(false);
            dayLogs[index] = !dayLogs[index];
            return { ...prev, [date]: dayLogs };
        });
    };

    const getDayChecks = (date: string) => {
        return logs[date] || Array(MAX_HABITS).fill(false);
    };

    // Nav Items
    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <ChartBarIcon className="w-5 h-5"/> },
        { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-5 h-5"/> },
        { id: 'reports', label: 'Reports', icon: <ListIcon className="w-5 h-5"/> },
        { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5"/> },
    ];

    // Render Logic for Views
    const renderDashboard = () => (
        <div className="space-y-8 animate-fade-in">
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                 <StatCard label="Current Streak" value={`${stats.streak} Days`} icon={<FireIcon className="w-6 h-6"/>} color="bg-orange-500" />
                 <StatCard label="Perfect Days" value={stats.perfectDays} icon={<CheckIcon className="w-6 h-6"/>} color="bg-green-500" />
                 <StatCard label="Total Habits" value={stats.totalHabitsCompleted} icon={<ListIcon className="w-6 h-6"/>} color="bg-blue-500" />
                 <StatCard label="Completion Rate" value={`${stats.totalLoggedDays > 0 ? Math.round((stats.totalHabitsCompleted / (stats.totalLoggedDays * 10)) * 100) : 0}%`} icon={<ChartBarIcon className="w-6 h-6"/>} color="bg-purple-500" />
             </div>

             {/* Today's Focus Card */}
             <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-700 overflow-hidden">
                 <div className="p-6 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center">
                     <div>
                         <h3 className="text-lg font-bold text-slate-900 dark:text-white">Today's Discipline</h3>
                         <p className="text-slate-500 text-sm">{format(new Date(), 'EEEE, MMMM do')}</p>
                     </div>
                     <button 
                        onClick={() => setSelectedDate(today)}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-sm font-bold shadow-lg shadow-indigo-500/30 transition-all transform hover:scale-105"
                     >
                        {logs[today] ? 'Edit Report' : 'Start Report'}
                     </button>
                 </div>
                 <div className="p-6 bg-slate-50 dark:bg-slate-800/50">
                     <div className="flex gap-2 mb-2">
                        {Array.from({length: 10}).map((_, i) => (
                            <div key={i} className={`h-2 flex-1 rounded-full ${getDayChecks(today)[i] ? 'bg-green-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                        ))}
                     </div>
                     <p className="text-xs text-center text-slate-400 font-bold uppercase tracking-wider">
                         {getDayChecks(today).filter(Boolean).length} / 10 Completed
                     </p>
                 </div>
             </div>

             {/* Recent Activity Mini-List */}
             <div>
                 <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">Recent Days</h3>
                 <div className="space-y-3">
                     {[1, 2, 3, 4, 5].map(daysAgo => {
                         const d = subDays(new Date(), daysAgo);
                         const dStr = format(d, 'yyyy-MM-dd');
                         const count = getDayChecks(dStr).filter(Boolean).length;
                         return (
                             <div key={dStr} onClick={() => setSelectedDate(dStr)} className="flex items-center justify-between p-4 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 hover:border-indigo-400 cursor-pointer transition-colors group">
                                 <div className="flex items-center gap-4">
                                     <div className={`w-3 h-10 rounded-full ${getScoreColor(count).split(' ')[0]}`}></div>
                                     <div>
                                         <p className="font-bold text-slate-800 dark:text-slate-200">{format(d, 'MMMM do')}</p>
                                         <p className="text-xs text-slate-500">{format(d, 'EEEE')}</p>
                                     </div>
                                 </div>
                                 <div className="flex items-center gap-3">
                                     <span className="text-sm font-mono font-bold text-slate-400">{count}/10</span>
                                     <ChevronRightIcon className="w-4 h-4 text-slate-300 group-hover:text-indigo-500 -rotate-90" />
                                 </div>
                             </div>
                         )
                     })}
                 </div>
             </div>
        </div>
    );

    const renderCalendar = () => {
        // Generate days for current month view
        const monthStart = startOfMonth(currentMonth);
        const monthEnd = endOfMonth(currentMonth);
        const startDate = startOfWeek(monthStart);
        const endDate = endOfWeek(monthEnd);
        const daysInMonth = eachDayOfInterval({ start: startDate, end: endDate });

        // Generate year heatmap (GitHub style) - simplified for last 365 days
        const yearStart = subDays(new Date(), 364);
        const yearDays = eachDayOfInterval({ start: yearStart, end: new Date() });

        return (
            <div className="space-y-8 animate-fade-in h-full flex flex-col">
                {/* Year Heatmap */}
                <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-x-auto">
                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4">Yearly Consistency</h3>
                    <div className="flex gap-1 min-w-max">
                        {/* Group by weeks roughly for visual structure */}
                        {Array.from({ length: 53 }).map((_, weekIdx) => (
                            <div key={weekIdx} className="flex flex-col gap-1">
                                {Array.from({ length: 7 }).map((_, dayIdx) => {
                                    const dayIndex = weekIdx * 7 + dayIdx;
                                    if (dayIndex >= yearDays.length) return null;
                                    const day = yearDays[dayIndex];
                                    const dStr = format(day, 'yyyy-MM-dd');
                                    const count = getDayChecks(dStr).filter(Boolean).length;
                                    // Heatmap logic: 0=bg-slate-100, 1-3=red, 4-6=orange, 7-9=blue, 10=green
                                    let colorClass = 'bg-slate-100 dark:bg-slate-700';
                                    if (count === 10) colorClass = 'bg-green-500';
                                    else if (count >= 7) colorClass = 'bg-blue-500';
                                    else if (count >= 4) colorClass = 'bg-orange-400';
                                    else if (count > 0) colorClass = 'bg-red-400';

                                    return (
                                        <div 
                                            key={dStr} 
                                            onClick={() => setSelectedDate(dStr)}
                                            className={`w-3 h-3 rounded-sm cursor-pointer hover:ring-1 hover:ring-black dark:hover:ring-white transition-all ${colorClass}`} 
                                            title={`${dStr}: ${count}/10`}
                                        ></div>
                                    )
                                })}
                            </div>
                        ))}
                    </div>
                </div>

                {/* Monthly Detail View */}
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm flex-1 flex flex-col">
                    <div className="p-4 border-b border-slate-100 dark:border-slate-700 flex items-center justify-between">
                        <h2 className="text-xl font-bold text-slate-800 dark:text-white">{format(currentMonth, 'MMMM yyyy')}</h2>
                        <div className="flex gap-2">
                            <button onClick={() => setCurrentMonth(subDays(currentMonth, 30))} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700"><ChevronLeftIcon className="w-5 h-5"/></button>
                            <button onClick={() => setCurrentMonth(new Date())} className="px-3 py-1 text-xs font-bold bg-slate-100 dark:bg-slate-700 rounded-lg">Today</button>
                            <button onClick={() => setCurrentMonth(new Date(currentMonth.setMonth(currentMonth.getMonth() + 1)))} className="p-2 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700"><ChevronRightIcon className="w-5 h-5 transform -rotate-90"/></button>
                        </div>
                    </div>
                    <div className="grid grid-cols-7 text-center py-2 border-b border-slate-100 dark:border-slate-700 text-xs font-bold text-slate-400 uppercase">
                        <div>Sun</div><div>Mon</div><div>Tue</div><div>Wed</div><div>Thu</div><div>Fri</div><div>Sat</div>
                    </div>
                    <div className="grid grid-cols-7 flex-1">
                        {daysInMonth.map(day => {
                            const dStr = format(day, 'yyyy-MM-dd');
                            const count = getDayChecks(dStr).filter(Boolean).length;
                            const isCurrentMonth = day.getMonth() === currentMonth.getMonth();
                            const isTodayDate = isToday(day);
                            const hasData = logs[dStr] !== undefined;

                            let ringColor = 'ring-slate-200 dark:ring-slate-700'; // default
                            if (count === 10) ringColor = 'ring-green-500 bg-green-50 dark:bg-green-900/20';
                            else if (count >= 6) ringColor = 'ring-blue-500 bg-blue-50 dark:bg-blue-900/20';
                            else if (count >= 3) ringColor = 'ring-orange-500 bg-orange-50 dark:bg-orange-900/20';
                            else if (count > 0 || hasData) ringColor = 'ring-red-500 bg-red-50 dark:bg-red-900/20';

                            return (
                                <div 
                                    key={dStr} 
                                    onClick={() => setSelectedDate(dStr)}
                                    className={`
                                        min-h-[80px] p-2 border-r border-b border-slate-100 dark:border-slate-700/50 cursor-pointer transition-all hover:bg-slate-50 dark:hover:bg-slate-700/30 flex flex-col justify-between
                                        ${!isCurrentMonth ? 'bg-slate-50/50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600' : ''}
                                    `}
                                >
                                    <div className="flex justify-between items-start">
                                        <span className={`text-sm font-semibold ${isTodayDate ? 'bg-indigo-600 text-white px-2 py-0.5 rounded-full' : ''}`}>{format(day, 'd')}</span>
                                        {count === 10 && <CheckIcon className="w-4 h-4 text-green-500" />}
                                    </div>
                                    <div className={`mt-2 h-1.5 w-full rounded-full ring-1 ring-inset ${ringColor}`}></div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        );
    };

    const renderSettings = () => (
        <div className="max-w-2xl mx-auto space-y-8 animate-fade-in">
            <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <h3 className="text-lg font-bold text-slate-900 dark:text-white mb-4 flex items-center gap-2">
                    <PencilIcon className="w-5 h-5 text-indigo-500" />
                    Edit Daily Habits
                </h3>
                <p className="text-sm text-slate-500 dark:text-slate-400 mb-6">
                    Define the 10 disciplines you commit to every single day. Changing these will update the labels for all days (past and future).
                </p>
                <div className="space-y-3">
                    {habitNames.map((name, idx) => (
                        <div key={idx} className="flex items-center gap-3">
                            <span className="text-xs font-mono font-bold text-slate-400 w-6 text-right">{(idx + 1).toString().padStart(2, '0')}</span>
                            <input 
                                type="text" 
                                value={name} 
                                onChange={(e) => {
                                    const newNames = [...habitNames];
                                    newNames[idx] = e.target.value;
                                    setHabitNames(newNames);
                                }}
                                className="flex-1 modern-input"
                                placeholder={`Habit ${idx + 1}`}
                            />
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-red-50 dark:bg-red-900/10 p-6 rounded-2xl border border-red-100 dark:border-red-900/30">
                <h3 className="text-lg font-bold text-red-700 dark:text-red-400 mb-2">Danger Zone</h3>
                <p className="text-sm text-red-600/70 dark:text-red-300/70 mb-4">Clear all habit history. This cannot be undone.</p>
                <button 
                    onClick={() => {
                        if(window.confirm("Are you sure you want to delete all habit logs?")) {
                            setLogs({});
                        }
                    }}
                    className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white text-sm font-bold rounded-lg transition-colors"
                >
                    Reset All Data
                </button>
            </div>
        </div>
    );

    const renderReports = () => {
        // Group by month
        const entries = Object.entries(logs).sort((a, b) => b[0].localeCompare(a[0]));

        return (
            <div className="space-y-6 animate-fade-in">
                 <h2 className="text-2xl font-bold text-slate-800 dark:text-white">Daily Logs</h2>
                 <div className="space-y-2">
                     {entries.map(([date, checks]) => {
                         const count = checks.filter(Boolean).length;
                         return (
                            <div key={date} onClick={() => setSelectedDate(date)} className="group flex items-center justify-between p-4 bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 hover:border-indigo-400 cursor-pointer transition-all">
                                <div className="flex items-center gap-4">
                                     <div className={`w-12 h-12 rounded-lg flex items-center justify-center font-bold text-lg text-white ${getScoreColor(count).split(' ')[0]}`}>
                                         {count}
                                     </div>
                                     <div>
                                         <p className="font-bold text-slate-800 dark:text-slate-100">{format(parseISO(date), 'MMMM do, yyyy')}</p>
                                         <p className="text-xs text-slate-500 dark:text-slate-400">{format(parseISO(date), 'EEEE')}</p>
                                     </div>
                                </div>
                                <ChevronRightIcon className="w-5 h-5 text-slate-300 group-hover:text-indigo-500 -rotate-90 transition-colors" />
                            </div>
                         );
                     })}
                     {entries.length === 0 && (
                         <div className="text-center py-20 text-slate-400">No history available yet.</div>
                     )}
                 </div>
            </div>
        );
    };

    return (
        <div className="h-full w-full flex flex-col md:flex-row bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            <HabitModal 
                isOpen={!!selectedDate} 
                date={selectedDate || today} 
                onClose={() => setSelectedDate(null)} 
                habits={habitNames}
                checks={selectedDate ? getDayChecks(selectedDate) : []}
                onToggle={(idx) => selectedDate && handleToggleHabit(selectedDate, idx)}
            />

            {/* Sidebar (Desktop) / Header (Mobile) */}
            <aside className={`
                fixed inset-y-0 left-0 z-30 w-64 bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0 flex flex-col
                ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'}
            `}>
                <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex items-center gap-3">
                    <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg text-emerald-600 dark:text-emerald-400">
                        <ClockIcon className="w-6 h-6" />
                    </div>
                    <h1 className="font-extrabold text-xl tracking-tight text-slate-900 dark:text-white">Consistency</h1>
                    <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden ml-auto p-1 text-slate-400"><XCircleIcon className="w-6 h-6"/></button>
                </div>

                <nav className="p-4 space-y-2 flex-1">
                    {navItems.map(item => (
                        <button
                            key={item.id}
                            onClick={() => { setView(item.id as any); setIsMobileMenuOpen(false); }}
                            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all ${
                                view === item.id 
                                ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400' 
                                : 'text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'
                            }`}
                        >
                            {item.icon}
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div className="p-4 border-t border-slate-100 dark:border-slate-800">
                    <div onClick={onClose} className="flex items-center gap-3 px-4 py-3 text-sm font-bold text-slate-400 hover:text-slate-600 cursor-pointer transition-colors">
                        <ChevronLeftIcon className="w-5 h-5" /> Back to OS
                    </div>
                </div>
            </aside>

            {/* Mobile Header Overlay */}
            <div className="md:hidden p-4 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between sticky top-0 z-20">
                 <div className="flex items-center gap-2 font-bold text-slate-900 dark:text-white">
                     <ClockIcon className="w-5 h-5 text-emerald-500" /> Consistency
                 </div>
                 <button onClick={() => setIsMobileMenuOpen(true)} className="p-2 text-slate-600 dark:text-slate-300">
                     <MenuIcon className="w-6 h-6" />
                 </button>
            </div>

            {isMobileMenuOpen && <div className="fixed inset-0 bg-black/50 z-20 md:hidden" onClick={() => setIsMobileMenuOpen(false)}></div>}

            {/* Main Content */}
            <main className="flex-1 overflow-y-auto p-4 sm:p-8 bg-slate-50 dark:bg-slate-950/50 relative">
                <div className="max-w-5xl mx-auto h-full flex flex-col">
                    <header className="mb-8">
                        <h2 className="text-3xl font-extrabold text-slate-900 dark:text-white capitalize">{view}</h2>
                        <p className="text-slate-500 dark:text-slate-400 mt-1">
                            {view === 'dashboard' && "Track your daily discipline."}
                            {view === 'calendar' && "Visualize your consistency over time."}
                            {view === 'reports' && "Detailed history of your habits."}
                            {view === 'settings' && "Configure your 10 core habits."}
                        </p>
                    </header>

                    <div className="flex-1 min-h-0">
                        {view === 'dashboard' && renderDashboard()}
                        {view === 'calendar' && renderCalendar()}
                        {view === 'reports' && renderReports()}
                        {view === 'settings' && renderSettings()}
                    </div>
                </div>
            </main>
        </div>
    );
};

