const HabitTrackerPage: React.FC<HabitTrackerProps> = ({ user, onClose }) => {
    const [view, setView] = useState<'dashboard' | 'calendar' | 'reports' | 'settings'>('dashboard');
    const [habitNames, setHabitNames] = useLocalStorage<string[]>(`habit-names-${user.id}`, DEFAULT_HABITS);
    const [logs, setLogs] = useLocalStorage<HabitLog>(`habit-logs-${user.id}`, {});
    const [selectedDate, setSelectedDate] = useState<string | null>(null);

    // Calendar View State
    const [currentYear, setCurrentYear] = useState(new Date().getFullYear());
    const [currentMonth, setCurrentMonth] = useState(new Date());

    const today = format(new Date(), 'yyyy-MM-dd');
    const todayChecks = logs[today] || Array(MAX_HABITS).fill(false);
    const todayCompleted = todayChecks.filter(Boolean).length;

    // Stats Logic
    const stats = useMemo(() => {
        const entries = Object.entries(logs);
        const totalLoggedDays = entries.length;
        const totalHabitsCompleted = entries.reduce((acc, [_, checks]) => acc + checks.filter(Boolean).length, 0);
        const perfectDays = entries.filter(([_, checks]) => checks.filter(Boolean).length === MAX_HABITS).length;

        // Calculate Streak
        let streak = 0;
        const sortedDates = Object.keys(logs).sort().reverse();
        if (sortedDates.length > 0) {
            let currentDate = new Date();
            // Allow skipping today if not yet logged, start check from yesterday
            if (!logs[format(currentDate, 'yyyy-MM-dd')] || logs[format(currentDate, 'yyyy-MM-dd')].filter(Boolean).length === 0) {
                currentDate = subDays(currentDate, 1);
            }

            // Iterate backwards
            for (let i = 0; i < 365; i++) { // Limit check to a year
                 const dStr = format(currentDate, 'yyyy-MM-dd');
                 if (logs[dStr] && logs[dStr].some(Boolean)) {
                     streak++;
                     currentDate = subDays(currentDate, 1);
                 } else {
                     break;
                 }
            }
        }

        return { totalLoggedDays, totalHabitsCompleted, perfectDays, streak };
    }, [logs]);

    const handleToggleHabit = (date: string, index: number) => {
        setLogs(prev => {
            const dayLogs = prev[date] ? [...prev[date]] : Array(MAX_HABITS).fill(false);
            dayLogs[index] = !dayLogs[index];
            return { ...prev, [date]: dayLogs };
        });
    };

    const getDayChecks = (date: string) => {
        return logs[date] || Array(MAX_HABITS).fill(false);
    };

    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <FireIcon className="w-5 h-5" /> },
        { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-5 h-5" /> },
        { id: 'reports', label: 'Reports', icon: <ChartBarIcon className="w-5 h-5" /> },
        { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5" /> },
    ];

    // --- View Renderers ---

    const renderDashboard = () => (
        <div className="space-y-8 animate-fade-in pb-10">
             {/* Main Hero Card */}
             <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden relative group">
                 <div className="absolute top-0 left-0 w-full h-1.5 bg-slate-100 dark:bg-slate-700">
                     <div className={`h-full transition-all duration-700 ${getScoreColor(todayCompleted)}`} style={{ width: `${(todayCompleted / 10) * 100}%` }}></div>
                 </div>
                 <div className="p-6 sm:p-8">
                     <div className="flex justify-between items-start mb-6">
                         <div>
                             <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{format(new Date(), 'EEEE, MMMM do')}</p>
                             <h2 className="text-3xl sm:text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight">Today's Focus</h2>
                         </div>
                         <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-bold text-lg shadow-lg ${getScoreColor(todayCompleted)}`}>
                             {todayCompleted}
                         </div>
                     </div>

                     <p className="text-slate-600 dark:text-slate-400 mb-8 max-w-lg">
                        {todayCompleted === 10 
                            ? "You've crushed it today! Consistency is the key to greatness." 
                            : "Keep pushing. Every checked box is a step towards a better you."}
                     </p>

                     <button 
                        onClick={() => setSelectedDate(today)}
                        className={`
                            w-full sm:w-auto px-8 py-4 rounded-xl font-bold text-white shadow-lg shadow-indigo-500/20 transition-all transform hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-2
                            ${todayCompleted === 10 ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}
                        `}
                     >
                        {todayCompleted === 10 ? <CheckIcon className="w-5 h-5"/> : <PencilIcon className="w-5 h-5"/>}
                        {todayCompleted === 10 ? 'View Report' : 'Log Habits'}
                     </button>
                 </div>
             </div>

             {/* Stats Grid */}
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                 <StatCard label="Current Streak" value={`${stats.streak} Days`} icon={<FireIcon className="w-6 h-6"/>} colorClass="bg-orange-500" textColorClass="text-orange-600 dark:text-orange-400" />
                 <StatCard label="Perfect Days" value={stats.perfectDays} icon={<CheckIcon className="w-6 h-6"/>} colorClass="bg-green-500" textColorClass="text-green-600 dark:text-green-400" />
                 <StatCard label="Total Habits" value={stats.totalHabitsCompleted} icon={<ListIcon className="w-6 h-6"/>} colorClass="bg-blue-500" textColorClass="text-blue-600 dark:text-blue-400" />
                 <StatCard label="Consistency" value={`${stats.totalLoggedDays > 0 ? Math.round((stats.totalHabitsCompleted / (stats.totalLoggedDays * 10)) * 100) : 0}%`} icon={<ChartBarIcon className="w-6 h-6"/>} colorClass="bg-purple-500" textColorClass="text-purple-600 dark:text-purple-400" />
             </div>

             {/* Recent History Strip */}
             <div>
                 <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 px-1">Last 5 Days</h3>
                 <div className="grid grid-cols-5 gap-2 sm:gap-4">
                     {[4, 3, 2, 1, 0].map(daysAgo => {
                         const d = subDays(new Date(), daysAgo);
                         const dStr = format(d, 'yyyy-MM-dd');
                         const count = getDayChecks(dStr).filter(Boolean).length;
                         const isTodayDate = daysAgo === 0;

                         return (
                             <button 
                                key={dStr} 
                                onClick={() => setSelectedDate(dStr)}
                                className={`
                                    flex flex-col items-center justify-center p-3 sm:p-4 rounded-xl border transition-all hover:-translate-y-1
                                    ${isTodayDate ? 'bg-white dark:bg-slate-800 border-indigo-500 ring-1 ring-indigo-500 shadow-md' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}
                                `}
                             >
                                 <span className="text-[10px] font-bold text-slate-400 uppercase mb-1">{format(d, 'EEE')}</span>
                                 <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold text-white mb-1 ${getScoreColor(count)}`}>
                                     {format(d, 'd')}
                                 </div>
                                 <div className="w-full h-1 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden mt-1">
                                     <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                 </div>
                             </button>
                         )
                     })}
                 </div>
             </div>
        </div>
    );

    const renderCalendar = () => {
        // Month Grid Logic
        const monthStart = startOfMonth(currentMonth);
        const monthEnd = endOfMonth(currentMonth);
        const startDate = startOfWeek(monthStart);
        const endDate = endOfWeek(monthEnd);
        const daysInMonth = eachDayOfInterval({ start: startDate, end: endDate });

        // Generate months for the year heatmap
        const yearMonths = Array.from({ length: 12 }, (_, i) => new Date(currentYear, i, 1));

        return (
            <div className="space-y-8 animate-fade-in pb-10">
                {/* Month View (Large) */}
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                    <div className="p-4 sm:p-6 border-b border-slate-100 dark:border-slate-700 flex items-center justify-between bg-slate-50 dark:bg-slate-800/50">
                        <h2 className="text-xl font-bold text-slate-800 dark:text-white">{format(currentMonth, 'MMMM yyyy')}</h2>
                        <div className="flex gap-1 bg-white dark:bg-slate-900 rounded-lg p-1 border border-slate-200 dark:border-slate-700 shadow-sm">
                            <button onClick={() => setCurrentMonth(subMonths(currentMonth, 1))} className="p-1.5 rounded-md hover:bg-slate-100 dark:hover:bg-slate-800"><ChevronDownIcon className="w-4 h-4 rotate-90"/></button>
                            <button onClick={() => setCurrentMonth(new Date())} className="px-3 py-1 text-xs font-bold bg-slate-100 dark:bg-slate-800 rounded-md">Today</button>
                            <button onClick={() => setCurrentMonth(addMonths(currentMonth, 1))} className="p-1.5 rounded-md hover:bg-slate-100 dark:hover:bg-slate-800"><ChevronDownIcon className="w-4 h-4 -rotate-90"/></button>
                        </div>
                    </div>
                    <div className="grid grid-cols-7 text-center py-3 border-b border-slate-100 dark:border-slate-700 text-xs font-bold text-slate-400 uppercase tracking-wider bg-white dark:bg-slate-800">
                        <div>Sun</div><div>Mon</div><div>Tue</div><div>Wed</div><div>Thu</div><div>Fri</div><div>Sat</div>
                    </div>
                    <div className="grid grid-cols-7 bg-slate-200 dark:bg-slate-700 gap-px">
                        {daysInMonth.map(day => {
                            const dStr = format(day, 'yyyy-MM-dd');
                            const count = getDayChecks(dStr).filter(Boolean).length;
                            const isCurrentMonth = isSameMonth(day, currentMonth);
                            const isTodayDate = isToday(day);

                            // Determine cell style
                            let cellBg = 'bg-white dark:bg-slate-800';
                            if (!isCurrentMonth) cellBg = 'bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600';

                            return (
                                <button 
                                    key={dStr} 
                                    onClick={() => setSelectedDate(dStr)}
                                    className={`
                                        h-24 sm:h-28 p-2 flex flex-col justify-between items-start transition-colors hover:bg-indigo-50 dark:hover:bg-indigo-900/10 relative group
                                        ${cellBg}
                                    `}
                                >
                                    <div className="flex justify-between w-full">
                                        <span className={`text-sm font-semibold w-7 h-7 flex items-center justify-center rounded-full ${isTodayDate ? 'bg-indigo-600 text-white' : ''}`}>
                                            {format(day, 'd')}
                                        </span>
                                        {count === 10 && <div className="text-green-500"><CheckIcon className="w-4 h-4"/></div>}
                                    </div>

                                    <div className="w-full space-y-1">
                                        {/* Progress Bar Visual for Day */}
                                        <div className="w-full bg-slate-100 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                                            <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                        </div>
                                        <div className="text-[10px] font-bold text-slate-400 text-right">{count}/10</div>
                                    </div>
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Year Glance (Heatmap) */}
                <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-x-auto">
                    <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-6">Yearly Overview ({currentYear})</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {yearMonths.map(month => (
                            <div key={month.toString()} className="space-y-2">
                                <h4 className="text-xs font-bold text-slate-800 dark:text-slate-200">{format(month, 'MMMM')}</h4>
                                <div className="grid grid-cols-7 gap-1">
                                    {eachDayOfInterval({ start: startOfMonth(month), end: endOfMonth(month) }).map(day => {
                                         const dStr = format(day, 'yyyy-MM-dd');
                                         const count = getDayChecks(dStr).filter(Boolean).length;
                                         // Mini heatmap cell
                                         return (
                                             <div 
                                                key={dStr}
                                                className={`w-full aspect-square rounded-sm ${getScoreColor(count)} opacity-80 hover:opacity-100 cursor-pointer`}
                                                title={`${dStr}: ${count}/10`}
                                                onClick={() => setSelectedDate(dStr)}
                                             ></div>
                                         )
                                    })}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        );
    };

    const renderReports = () => {
        const sortedDates = Object.keys(logs).sort().reverse();

        return (
            <div className="space-y-6 animate-fade-in pb-10">
                 <div className="flex items-center justify-between mb-2">
                    <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Daily Logs</h2>
                    <span className="text-sm text-slate-500">{sortedDates.length} entries</span>
                 </div>

                 <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm divide-y divide-slate-100 dark:divide-slate-700 overflow-hidden">
                     {sortedDates.length === 0 && (
                         <div className="p-12 text-center text-slate-500 dark:text-slate-400">
                             No data recorded yet. Start your journey today!
                         </div>
                     )}
                     {sortedDates.map(date => {
                         const count = getDayChecks(date).filter(Boolean).length;
                         return (
                             <div key={date} onClick={() => setSelectedDate(date)} className="p-4 sm:p-5 hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors flex items-center justify-between group">
                                 <div className="flex items-center gap-4">
                                     <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-lg text-white shadow-sm ${getScoreColor(count)}`}>
                                         {count}
                                     </div>
                                     <div>
                                         <p className="font-bold text-slate-900 dark:text-white">{format(parseISO(date), 'MMMM do, yyyy')}</p>
                                         <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wide">{format(parseISO(date), 'EEEE')}</p>
                                     </div>
                                 </div>
                                 <div className="flex items-center gap-4">
                                     <div className="hidden sm:block w-32 h-2 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                                         <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                     </div>
                                     <ChevronDownIcon className="w-5 h-5 text-slate-300 group-hover:text-indigo-500 -rotate-90 transition-colors" />
                                 </div>
                             </div>
                         );
                     })}
                 </div>
            </div>
        );
    };

    const renderSettings = () => (
        <div className="max-w-2xl mx-auto space-y-8 animate-fade-in pb-10">
            <div className="bg-white dark:bg-slate-800 p-6 sm:p-8 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-6 flex items-center gap-3">
                    <div className="p-2 bg-indigo-100 dark:bg-indigo-900/30 rounded-lg text-indigo-600 dark:text-indigo-400"><PencilIcon className="w-5 h-5" /></div>
                    Edit Daily Habits
                </h3>
                <div className="space-y-4">
                    {habitNames.map((name, idx) => (
                        <div key={idx} className="group">
                            <label className="block text-[10px] font-bold uppercase text-slate-400 mb-1 ml-1">Habit {idx + 1}</label>
                            <input 
                                type="text" 
                                value={name} 
                                onChange={(e) => {
                                    const newNames = [...habitNames];
                                    newNames[idx] = e.target.value;
                                    setHabitNames(newNames);
                                }}
                                className="modern-input w-full font-medium"
                                placeholder={`Enter habit ${idx + 1}`}
                            />
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-red-50 dark:bg-red-900/10 p-6 sm:p-8 rounded-2xl border border-red-100 dark:border-red-900/30">
                <h3 className="text-lg font-bold text-red-700 dark:text-red-400 mb-2">Danger Zone</h3>
                <p className="text-sm text-red-600/70 dark:text-red-300/70 mb-6">Clear all habit history. This cannot be undone.</p>
                <button 
                    onClick={() => {
                        if(window.confirm("Are you sure you want to delete all habit logs? This action is irreversible.")) {
                            setLogs({});
                        }
                    }}
                    className="px-6 py-3 bg-white border border-red-200 text-red-600 hover:bg-red-50 text-sm font-bold rounded-xl transition-colors shadow-sm"
                >
                    Reset All Data
                </button>
            </div>
        </div>
    );

    return (
        <div className="h-full w-full flex flex-col md:flex-row bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            {/* Modal is rendered via Portal inside HabitModal component */}
            <HabitModal 
                isOpen={!!selectedDate} 
                date={selectedDate || today} 
                onClose={() => setSelectedDate(null)} 
                habits={habitNames}
                checks={selectedDate ? getDayChecks(selectedDate) : []}
                onToggle={(idx) => selectedDate && handleToggleHabit(selectedDate, idx)}
            />

            {/* Desktop Sidebar */}
            <aside className="hidden md:flex flex-col w-64 lg:w-72 border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 z-10 flex-shrink-0">
                <div className="p-6 border-b border-slate-100 dark:border-slate-800">
                    <div className="flex items-center gap-3 mb-1">
                        <div className="p-2 bg-emerald-100 dark:bg-emerald-900/30 rounded-lg text-emerald-600 dark:text-emerald-400">
                            <ClockIcon className="w-6 h-6" />
                        </div>
                        <h1 className="font-extrabold text-xl tracking-tight text-slate-900 dark:text-white">Consistency</h1>
                    </div>
                    <p className="text-xs text-slate-400 pl-1">Build better habits.</p>
