                </div>
            </main>

            {/* Mobile Bottom Navigation - Use Absolute positioning to respect Window constraints properly */}
            <nav className="md:hidden absolute bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 z-50 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
                <div className="grid grid-cols-4 h-16">
