);

const HabitTrackerPage: React.FC<HabitTrackerProps> = ({ user, onClose }) => {
    const [view, setView] = useState<'dashboard' | 'calendar' | 'reports' | 'settings'>('dashboard');
    const [habitNames, setHabitNames] = useLocalStorage<string[]>(`habit-names-${user.id}`, DEFAULT_HABITS);
    const [dailyConfig, setDailyConfig] = useLocalStorage<Record<string, string[]>>(`habit-daily-config-${user.id}`, {});
    const [logs, setLogs] = useLocalStorage<HabitLog>(`habit-logs-${user.id}`, {});
    const [selectedDate, setSelectedDate] = useState<string | null>(null);

    // Calendar View State
    const [currentDate, setCurrentDate] = useState(new Date());
    const [calendarView, setCalendarView] = useState<'year' | 'month' | 'week'>('month');

    const today = format(new Date(), 'yyyy-MM-dd');
    const todayChecks = logs[today] || Array(MAX_HABITS).fill(false);
    const todayCompleted = todayChecks.filter(Boolean).length;

    // Helper to get habits for a specific date (merging overrides)
    const getHabitsForDate = (date: string) => {
        return dailyConfig[date] || habitNames;
    };

    // Stats Logic
    const stats = useMemo(() => {
        const entries = Object.entries(logs);
        const totalLoggedDays = entries.length;
        const totalHabitsCompleted = entries.reduce((acc, [_, checks]) => acc + checks.filter(Boolean).length, 0);
        const perfectDays = entries.filter(([_, checks]) => checks.filter(Boolean).length === MAX_HABITS).length;

        // Calculate Streak
        let streak = 0;
        let checkDate = new Date();
        if (!logs[format(checkDate, 'yyyy-MM-dd')] || logs[format(checkDate, 'yyyy-MM-dd')].filter(Boolean).length === 0) {
             checkDate = subDays(checkDate, 1);
        }

        for (let i = 0; i < 365; i++) {
             const dStr = format(checkDate, 'yyyy-MM-dd');
             if (logs[dStr] && logs[dStr].some(Boolean)) {
                 streak++;
                 checkDate = subDays(checkDate, 1);
             } else {
                 break;
             }
        }

        return { totalLoggedDays, totalHabitsCompleted, perfectDays, streak };
    }, [logs]);

    const handleToggleHabit = (date: string, index: number) => {
        if (date !== today) {
            // Cannot toggle past/future habits
            return;
        }
        setLogs(prev => {
            const dayLogs = prev[date] ? [...prev[date]] : Array(MAX_HABITS).fill(false);
            dayLogs[index] = !dayLogs[index];
            return { ...prev, [date]: dayLogs };
        });
    };

    const handleRenameHabit = (index: number, newName: string) => {
        if (!selectedDate) return;
        const currentList = [...getHabitsForDate(selectedDate)];
        currentList[index] = newName;
        setDailyConfig(prev => ({ ...prev, [selectedDate]: currentList }));
    };

    const handleResetDayHabits = () => {
        if (!selectedDate) return;
        const newConfig = { ...dailyConfig };
        delete newConfig[selectedDate];
        setDailyConfig(newConfig);
    };

    const getDayChecks = (date: string) => {
        return logs[date] || Array(MAX_HABITS).fill(false);
    };

    const navItems = [
        { id: 'dashboard', label: 'Dashboard', icon: <FireIcon className="w-5 h-5" /> },
        { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-5 h-5" /> },
        { id: 'reports', label: 'Reports', icon: <ChartBarIcon className="w-5 h-5" /> },
        { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-5 h-5" /> },
    ];

    // --- View Renderers ---
    const renderDashboard = () => (
        <div className="space-y-8 animate-fade-in pb-10">
             {/* Main Hero Card */}
             <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden relative group">
                 <div className="absolute top-0 left-0 w-full h-1.5 bg-slate-100 dark:bg-slate-700">
                     <div className={`h-full transition-all duration-700 ${getScoreColor(todayCompleted)}`} style={{ width: `${(todayCompleted / 10) * 100}%` }}></div>
                 </div>
                 <div className="p-6 sm:p-8">
                     <div className="flex justify-between items-start mb-6">
                         <div>
                             <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{format(new Date(), 'EEEE, MMMM do')}</p>
                             <h2 className="text-3xl sm:text-4xl font-extrabold text-slate-900 dark:text-white tracking-tight">Today's Focus</h2>
                         </div>
                         <div className={`w-12 h-12 rounded-full flex items-center justify-center text-white font-bold text-lg shadow-lg ${getScoreColor(todayCompleted)}`}>
                             {todayCompleted}
                         </div>
                     </div>

                     <p className="text-slate-600 dark:text-slate-400 mb-8 max-w-lg">
                        {todayCompleted === 10 
                            ? "You've crushed it today! Consistency is the key to greatness." 
                            : "Keep pushing. Every checked box is a step towards a better you."}
                     </p>

                     <button 
                        onClick={() => setSelectedDate(today)}
                        className={`
                            w-full sm:w-auto px-8 py-4 rounded-xl font-bold text-white shadow-lg shadow-indigo-500/20 transition-all transform hover:scale-[1.02] active:scale-95 flex items-center justify-center gap-2
                            ${todayCompleted === 10 ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}
                        `}
                     >
                        {todayCompleted === 10 ? <CheckIcon className="w-5 h-5"/> : <PencilIcon className="w-5 h-5"/>}
                        {todayCompleted === 10 ? 'View Report' : 'Log Habits'}
                     </button>
                 </div>
             </div>

             {/* Stats Grid */}
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                 <StatCard label="Current Streak" value={`${stats.streak} Days`} icon={<FireIcon className="w-6 h-6"/>} colorClass="bg-orange-500" textColorClass="text-orange-600 dark:text-orange-400" />
                 <StatCard label="Perfect Days" value={stats.perfectDays} icon={<CheckIcon className="w-6 h-6"/>} colorClass="bg-green-500" textColorClass="text-green-600 dark:text-green-400" />
                 <StatCard label="Total Habits" value={stats.totalHabitsCompleted} icon={<ListIcon className="w-6 h-6"/>} colorClass="bg-blue-500" textColorClass="text-blue-600 dark:text-blue-400" />
                 <StatCard label="Consistency" value={`${stats.totalLoggedDays > 0 ? Math.round((stats.totalHabitsCompleted / (stats.totalLoggedDays * 10)) * 100) : 0}%`} icon={<ChartBarIcon className="w-6 h-6"/>} colorClass="bg-purple-500" textColorClass="text-purple-600 dark:text-purple-400" />
             </div>

             {/* Recent History Strip */}
             <div>
                 <h3 className="text-sm font-bold text-slate-500 uppercase tracking-wider mb-4 px-1">Last 5 Days</h3>
                 <div className="grid grid-cols-5 gap-2 sm:gap-4">
                     {[4, 3, 2, 1, 0].map(daysAgo => {
                         const d = subDays(new Date(), daysAgo);
                         const dStr = format(d, 'yyyy-MM-dd');
                         const count = getDayChecks(dStr).filter(Boolean).length;
                         const isTodayDate = daysAgo === 0;

                         return (
                             <button 
                                key={dStr} 
                                onClick={() => setSelectedDate(dStr)}
                                className={`
                                    flex flex-col items-center justify-center p-3 sm:p-4 rounded-xl border transition-all hover:-translate-y-1
                                    ${isTodayDate ? 'bg-white dark:bg-slate-800 border-indigo-500 ring-1 ring-indigo-500 shadow-md' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}
                                `}
                             >
                                 <span className="text-[10px] font-bold text-slate-400 uppercase mb-1">{format(d, 'EEE')}</span>
                                 <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold text-white mb-1 ${getScoreColor(count)}`}>
                                     {format(d, 'd')}
                                 </div>
                                 <div className="w-full h-1 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden mt-1">
                                     <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                 </div>
                             </button>
                         )
                     })}
                 </div>
             </div>
        </div>
    );

    const renderCalendar = () => {
        const handlePrev = () => {
            if (calendarView === 'year') setCurrentDate(subYears(currentDate, 1));
            if (calendarView === 'month') setCurrentDate(subMonths(currentDate, 1));
            if (calendarView === 'week') setCurrentDate(subWeeks(currentDate, 1));
        };
        const handleNext = () => {
            if (calendarView === 'year') setCurrentDate(addYears(currentDate, 1));
            if (calendarView === 'month') setCurrentDate(addMonths(currentDate, 1));
            if (calendarView === 'week') setCurrentDate(addWeeks(currentDate, 1));
        };
        const handleToday = () => setCurrentDate(new Date());

        const daysInMonth = eachDayOfInterval({ 
            start: startOfWeek(startOfMonth(currentDate)), 
            end: endOfWeek(endOfMonth(currentDate)) 
        });

        return (
            <div className="space-y-6 animate-fade-in pb-10">
                {/* Header Controls */}
                <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                    <div className="flex p-1 bg-slate-100 dark:bg-slate-900 rounded-xl w-full sm:w-auto">
                        {(['week', 'month', 'year'] as const).map((v) => (
                            <button
                                key={v}
                                onClick={() => setCalendarView(v)}
                                className={`flex-1 sm:flex-none px-4 py-2 text-sm font-bold rounded-lg transition-all capitalize ${
                                    calendarView === v
                                    ? 'bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 shadow-sm'
                                    : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
                                }`}
                            >
                                {v}
                            </button>
                        ))}
                    </div>

                    <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                        <h2 className="text-lg font-bold text-slate-900 dark:text-white sm:w-48 text-center sm:text-right">
                            {calendarView === 'year' && format(currentDate, 'yyyy')}
                            {calendarView === 'month' && format(currentDate, 'MMMM yyyy')}
                            {calendarView === 'week' && `Week of ${format(startOfWeek(currentDate), 'MMM d')}`}
                        </h2>
                        <div className="flex gap-1 bg-slate-100 dark:bg-slate-900 rounded-lg p-1">
                            <button onClick={handlePrev} className="p-2 rounded-md hover:bg-white dark:hover:bg-slate-800 transition-colors"><ChevronDownIcon className="w-4 h-4 rotate-90"/></button>
                            <button onClick={handleToday} className="px-3 py-1 text-xs font-bold hover:bg-white dark:hover:bg-slate-800 rounded-md transition-colors">Today</button>
                            <button onClick={handleNext} className="p-2 rounded-md hover:bg-white dark:hover:bg-slate-800 transition-colors"><ChevronDownIcon className="w-4 h-4 -rotate-90"/></button>
                        </div>
                    </div>
                </div>

                {/* View Container */}
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden min-h-[400px]">
                    {calendarView === 'year' && (
                        <div className="p-6 overflow-x-auto">
                            <div className="min-w-[700px] grid grid-cols-3 gap-x-8 gap-y-8">
                                {Array.from({ length: 12 }).map((_, i) => {
                                    const monthDate = new Date(currentDate.getFullYear(), i, 1);
                                    const mDays = eachDayOfInterval({ start: startOfMonth(monthDate), end: endOfMonth(monthDate) });
                                    return (
                                        <div key={i} className="space-y-2">
                                            <h4 className="text-sm font-bold text-slate-500 dark:text-slate-400">{format(monthDate, 'MMMM')}</h4>
                                            <div className="grid grid-cols-7 gap-1">
                                                {mDays.map(d => {
                                                     const dStr = format(d, 'yyyy-MM-dd');
                                                     const count = getDayChecks(dStr).filter(Boolean).length;
                                                     return (
                                                         <div
                                                            key={dStr}
                                                            onClick={() => setSelectedDate(dStr)}
                                                            className={`w-full aspect-square rounded-sm cursor-pointer hover:opacity-80 transition-opacity ${getScoreColor(count)}`}
                                                            title={`${dStr}: ${count}/10`}
                                                         />
                                                     )
                                                })}
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    )}

                    {calendarView === 'month' && (
                        <>
                            <div className="grid grid-cols-7 text-center py-3 border-b border-slate-100 dark:border-slate-700 text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 dark:bg-slate-900/50">
                                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => <div key={d}>{d}</div>)}
                            </div>
                            <div className="grid grid-cols-7 bg-slate-200 dark:bg-slate-700 gap-px">
                                {daysInMonth.map(day => {
                                    const dStr = format(day, 'yyyy-MM-dd');
                                    const count = getDayChecks(dStr).filter(Boolean).length;
                                    const isCurrentMonth = isSameMonth(day, currentDate);
                                    const isTodayDate = isToday(day);

                                    return (
                                        <button 
                                            key={dStr} 
                                            onClick={() => setSelectedDate(dStr)}
                                            className={`
                                                h-24 sm:h-28 p-2 flex flex-col justify-between items-start transition-colors hover:bg-indigo-50 dark:hover:bg-indigo-900/10 relative group
                                                ${!isCurrentMonth ? 'bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600' : 'bg-white dark:bg-slate-800'}
                                            `}
                                        >
                                            <div className="flex justify-between w-full">
                                                <span className={`text-sm font-semibold w-7 h-7 flex items-center justify-center rounded-full ${isTodayDate ? 'bg-indigo-600 text-white' : ''}`}>
                                                    {format(day, 'd')}
                                                </span>
                                                {count === 10 && <div className="text-green-500"><CheckIcon className="w-4 h-4"/></div>}
                                            </div>
                                            <div className="w-full space-y-1">
                                                <div className="w-full bg-slate-100 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                                                    <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                                </div>
                                                <div className="text-[10px] font-bold text-slate-400 text-right">{count}/10</div>
                                            </div>
                                        </button>
                                    );
                                })}
                            </div>
                        </>
                    )}

                    {calendarView === 'week' && (
                        <div className="overflow-x-auto">
                            <div className="min-w-[800px]">
                                {/* Week Header */}
                                <div className="grid grid-cols-[200px_repeat(7,1fr)] border-b border-slate-200 dark:border-slate-700">
                                    <div className="p-4 font-bold text-slate-400 uppercase text-xs tracking-wider flex items-center bg-slate-50 dark:bg-slate-900/50">Habit (Default)</div>
                                    {eachDayOfInterval({
                                        start: startOfWeek(currentDate),
                                        end: endOfWeek(currentDate)
                                    }).map(day => (
                                        <div key={day.toString()} className={`p-4 text-center border-l border-slate-100 dark:border-slate-800 ${isToday(day) ? 'bg-indigo-50 dark:bg-indigo-900/20' : ''}`}>
                                            <div className="text-xs font-bold text-slate-500 uppercase">{format(day, 'EEE')}</div>
                                            <div className={`text-lg font-bold mt-1 ${isToday(day) ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{format(day, 'd')}</div>
                                        </div>
                                    ))}
                                </div>

                                {/* Habits Rows */}
                                {habitNames.map((habit, hIdx) => (
                                    <div key={hIdx} className="grid grid-cols-[200px_repeat(7,1fr)] border-b border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
