                                </div>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    const renderReports = () => {
        const sortedDates = Object.keys(logs).sort().reverse();

        // Calculate aggregations
        const aggregatedStats = useMemo(() => {
            const weeks: Record<string, { total: number; count: number; start: Date }> = {};
            const months: Record<string, { total: number; count: number; date: Date }> = {};
            const years: Record<string, { total: number; count: number; date: Date }> = {};

            Object.entries(logs).forEach(([dateStr, checks]) => {
                const date = parseISO(dateStr);
                const score = checks.filter(Boolean).length;

                // Weekly
                const weekStart = startOfWeek(date);
                const weekKey = format(weekStart, 'yyyy-MM-dd');
                if (!weeks[weekKey]) weeks[weekKey] = { total: 0, count: 0, start: weekStart };
                weeks[weekKey].total += score;
                weeks[weekKey].count += 1;

                // Monthly
                const monthKey = format(date, 'yyyy-MM');
                if (!months[monthKey]) months[monthKey] = { total: 0, count: 0, date };
                months[monthKey].total += score;
                months[monthKey].count += 1;

                // Yearly
                const yearKey = format(date, 'yyyy');
                if (!years[yearKey]) years[yearKey] = { total: 0, count: 0, date };
                years[yearKey].total += score;
                years[yearKey].count += 1;
            });

            return { 
                weeks: Object.values(weeks).sort((a,b) => b.start.getTime() - a.start.getTime()), 
                months: Object.values(months).sort((a,b) => b.date.getTime() - a.date.getTime()),
                years: Object.values(years).sort((a,b) => b.date.getTime() - a.date.getTime())
            };
        }, [logs]);

        return (
            <div className="space-y-6 animate-fade-in pb-10">
                 <div className="flex flex-col sm:flex-row items-center justify-between gap-4 mb-4">
                    <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Statistics & History</h2>

                    <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg">
                        {(['log', 'week', 'month', 'year'] as const).map(v => (
                             <button
                                key={v}
                                onClick={() => setStatsView(v)}
                                className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all capitalize ${
                                    statsView === v 
                                    ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-sm' 
                                    : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200'
                                }`}
                             >
                                 {v}
                             </button>
                        ))}
                    </div>
                 </div>

                 {/* Render Views based on tab */}
                 <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">

                     {/* 1. Log View (Default) */}
                     {statsView === 'log' && (
                         <div className="divide-y divide-slate-100 dark:divide-slate-700">
                            {sortedDates.length === 0 && (
                                <div className="p-12 text-center text-slate-500 dark:text-slate-400">
                                    No data recorded yet.
                                </div>
                            )}
                            {sortedDates.map(date => {
                                const count = getDayChecks(date).filter(Boolean).length;
                                return (
                                    <div key={date} onClick={() => setSelectedDate(date)} className="p-4 sm:p-5 hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors flex items-center justify-between group">
                                        <div className="flex items-center gap-4">
                                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-lg text-white shadow-sm ${getScoreColor(count)}`}>
                                                {count}
                                            </div>
                                            <div>
                                                <p className="font-bold text-slate-900 dark:text-white">{format(parseISO(date), 'MMMM do, yyyy')}</p>
                                                <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wide">{format(parseISO(date), 'EEEE')}</p>
                                            </div>
                                        </div>
                                        <ChevronDownIcon className="w-5 h-5 text-slate-300 group-hover:text-indigo-500 -rotate-90 transition-colors" />
                                    </div>
                                );
                            })}
                         </div>
                     )}

                     {/* 2. Weekly View */}
                     {statsView === 'week' && (
                         <div className="divide-y divide-slate-100 dark:divide-slate-700">
                            {aggregatedStats.weeks.length === 0 && <div className="p-12 text-center text-slate-500">No data available.</div>}
                            {aggregatedStats.weeks.map((week, idx) => {
                                const avg = week.total / week.count; // Average habits per day this week
                                const pct = (avg / 10) * 100;
                                return (
                                    <div key={idx} className="p-5 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                                        <div>
                                            <p className="font-bold text-slate-900 dark:text-white">Week of {format(week.start, 'MMM do, yyyy')}</p>
