// --- Constants & Types ---
const MAX_HABITS = 10;

interface HabitLog {
    [date: string]: boolean[]; // 'YYYY-MM-DD': [true, false, ...]
}

interface HabitTrackerProps {
    user: User;
    onClose?: () => void;
}

const DEFAULT_HABITS = [
    "Wake up by 6 AM",
    "Exercise / Workout",
    "Read 10 pages",
    "Deep Work (2 hrs)",
    "Drink 3L Water",
    "Meditate (10 mins)",
    "No Sugar",
    "Review Goals",
    "Code / Skill Practice",
    "Sleep by 11 PM"
];

const getScoreColor = (count: number, isBg = true) => {
    if (count === 10) return isBg ? 'bg-green-500' : 'text-green-500';
    if (count >= 6) return isBg ? 'bg-blue-500' : 'text-blue-500';
    if (count >= 3) return isBg ? 'bg-orange-500' : 'text-orange-500';
    if (count > 0) return isBg ? 'bg-red-500' : 'text-red-500';
    return isBg ? 'bg-slate-200 dark:bg-slate-700' : 'text-slate-300 dark:text-slate-600';
};

