const DonutChart: React.FC<{ data: { label: string; value: number; color: string }[], total: number }> = ({ data, total }) => {
    if (total === 0) return <div className="h-48 flex items-center justify-center text-slate-400 text-sm">No data to display</div>;

    let cumulativePercent = 0;
    const conicSegments = data.map((d) => {
        const start = cumulativePercent;
        const percent = (d.value / total) * 100;
        const end = start + percent;
        cumulativePercent = end;
        return `${d.color} ${start}% ${end}%`;
    }).join(', ');

    return (
        <div className="flex flex-col sm:flex-row items-center gap-8 justify-center p-4">
            <div className="relative w-48 h-48 flex-shrink-0">
                <div 
                    className="w-full h-full rounded-full shadow-lg"
                    style={{ background: `conic-gradient(${conicSegments})` }}
                ></div>
                <div className="absolute inset-8 bg-white dark:bg-slate-900 rounded-full flex flex-col items-center justify-center">
                    <span className="text-3xl font-black text-slate-800 dark:text-white">{total}</span>
                    <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Days Logged</span>
                </div>
            </div>
            <div className="space-y-3 w-full sm:w-auto min-w-[160px]">
                {data.map(item => (
                    <div key={item.label} className="flex items-center justify-between gap-3 group">
                        <div className="flex items-center gap-2">
                            <div className="w-3 h-3 rounded-full" style={{ backgroundColor: item.color }}></div>
                            <span className="text-sm font-medium text-slate-600 dark:text-slate-300 group-hover:text-slate-900 dark:group-hover:text-white transition-colors">{item.label}</span>
                        </div>
                        <span className="text-sm font-bold text-slate-800 dark:text-white">{Math.round((item.value/total)*100)}%</span>
                    </div>
                ))}
            </div>
        </div>
    );
}

const HorizontalBarChart: React.FC<{ data: { label: string; value: number; color: string; percentage: number }[] }> = ({ data }) => {
    if (data.length === 0 || data.every(d => d.value === 0)) return <div className="h-48 flex items-center justify-center text-slate-400 text-sm">No activity recorded yet</div>;

