const MONTH_PALETTES = [
    { name: 'Jan', styles: ['bg-indigo-200', 'bg-indigo-400', 'bg-indigo-600', 'bg-indigo-800'] },
    { name: 'Feb', styles: ['bg-pink-200', 'bg-pink-400', 'bg-pink-600', 'bg-pink-800'] },
