const CalendarView: React.FC<{
    getDayChecks: (d: string) => boolean[],
    onSelectDate: (d: string) => void,
    habitNames: string[],
    onToggleHabit: (d: string, i: number) => void
}> = ({ getDayChecks, onSelectDate, habitNames, onToggleHabit }) => {
    const [currentDate, setCurrentDate] = useState(new Date());
    const [calendarView, setCalendarView] = useState<'year' | 'month' | 'week'>('month');

    const handlePrev = () => {
        if (calendarView === 'year') setCurrentDate(subYears(currentDate, 1));
        if (calendarView === 'month') setCurrentDate(subMonths(currentDate, 1));
        if (calendarView === 'week') setCurrentDate(subWeeks(currentDate, 1));
    };
    const handleNext = () => {
        if (calendarView === 'year') setCurrentDate(addYears(currentDate, 1));
        if (calendarView === 'month') setCurrentDate(addMonths(currentDate, 1));
        if (calendarView === 'week') setCurrentDate(addWeeks(currentDate, 1));
    };
    const handleToday = () => setCurrentDate(new Date());

    const daysInMonth = eachDayOfInterval({ 
        start: startOfWeek(startOfMonth(currentDate)), 
        end: endOfWeek(endOfMonth(currentDate)) 
    });

    return (
        <div className="space-y-6 animate-fade-in pb-10" key={habitNames.join(',')}>
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white dark:bg-slate-800 p-4 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm">
                <div className="flex p-1 bg-slate-100 dark:bg-slate-900 rounded-xl w-full sm:w-auto">
                    {(['week', 'month', 'year'] as const).map((v) => (
                        <button
                            key={v}
                            onClick={() => setCalendarView(v)}
                            className={`flex-1 sm:flex-none px-4 py-2 text-sm font-bold rounded-lg transition-all capitalize ${
                                calendarView === v
                                ? 'bg-white dark:bg-slate-800 text-indigo-600 dark:text-indigo-400 shadow-sm'
                                : 'text-slate-500 dark:text-slate-400 hover:text-slate-700 dark:hover:text-slate-200'
                            }`}
                        >
                            {v}
                        </button>
                    ))}
                </div>

                <div className="flex items-center gap-4 w-full sm:w-auto justify-between sm:justify-end">
                    <h2 className="text-lg font-bold text-slate-900 dark:text-white sm:w-48 text-center sm:text-right">
                        {calendarView === 'year' && format(currentDate, 'yyyy')}
                        {calendarView === 'month' && format(currentDate, 'MMMM yyyy')}
                        {calendarView === 'week' && `Week of ${format(startOfWeek(currentDate), 'MMM d')}`}
                    </h2>
                    <div className="flex gap-1 bg-slate-100 dark:bg-slate-900 rounded-lg p-1">
                        <button onClick={handlePrev} className="p-2 rounded-md hover:bg-white dark:hover:bg-slate-800 transition-colors"><ChevronDownIcon className="w-4 h-4 rotate-90"/></button>
                        <button onClick={handleToday} className="px-3 py-1 text-xs font-bold hover:bg-white dark:hover:bg-slate-800 rounded-md transition-colors">Today</button>
                        <button onClick={handleNext} className="p-2 rounded-md hover:bg-white dark:hover:bg-slate-800 transition-colors"><ChevronDownIcon className="w-4 h-4 -rotate-90"/></button>
                    </div>
                </div>
            </div>

            <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden min-h-[400px]">
                {calendarView === 'year' && (
                    <div className="p-6 overflow-x-auto">
                        <div className="min-w-[700px] grid grid-cols-3 gap-x-8 gap-y-8">
                            {Array.from({ length: 12 }).map((_, i) => {
                                const monthDate = new Date(currentDate.getFullYear(), i, 1);
                                const mDays = eachDayOfInterval({ start: startOfMonth(monthDate), end: endOfMonth(monthDate) });
                                return (
                                    <div key={i} className="space-y-2">
                                        <h4 className={`text-sm font-bold ${MONTH_PALETTES[i].styles[3].replace('bg-', 'text-')} dark:${MONTH_PALETTES[i].styles[1].replace('bg-', 'text-')}`}>
                                            {format(monthDate, 'MMMM')}
                                        </h4>
                                        <div className="grid grid-cols-7 gap-1">
                                            {mDays.map(d => {
                                                 const dStr = format(d, 'yyyy-MM-dd');
                                                 const count = getDayChecks(dStr).filter(Boolean).length;
                                                 const colorClass = getMonthColor(i, count);
                                                 return (
                                                     <div
                                                        key={dStr}
                                                        onClick={() => onSelectDate(dStr)}
                                                        className={`w-full aspect-square rounded-sm cursor-pointer hover:opacity-80 transition-opacity ${colorClass}`}
                                                        title={`${dStr}: ${count}/10`}
                                                     />
                                                 )
                                            })}
                                        </div>
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                )}

                {calendarView === 'month' && (
                    <>
                        <div className="grid grid-cols-7 text-center py-3 border-b border-slate-100 dark:border-slate-700 text-xs font-bold text-slate-400 uppercase tracking-wider bg-slate-50 dark:bg-slate-900/50">
                            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(d => <div key={d}>{d}</div>)}
                        </div>
                        <div className="grid grid-cols-7 bg-slate-200 dark:bg-slate-700 gap-px">
                            {daysInMonth.map(day => {
                                const dStr = format(day, 'yyyy-MM-dd');
                                const count = getDayChecks(dStr).filter(Boolean).length;
                                const isCurrentMonth = isSameMonth(day, currentDate);
                                const isTodayDate = isToday(day);

                                return (
                                    <button 
                                        key={dStr} 
                                        onClick={() => onSelectDate(dStr)}
                                        className={`
                                            h-24 sm:h-28 p-2 flex flex-col justify-between items-start transition-colors hover:bg-indigo-50 dark:hover:bg-indigo-900/10 relative group
                                            ${!isCurrentMonth ? 'bg-slate-50 dark:bg-slate-900/50 text-slate-300 dark:text-slate-600' : 'bg-white dark:bg-slate-800'}
                                        `}
                                    >
                                        <div className="flex justify-between w-full">
                                            <span className={`text-sm font-semibold w-7 h-7 flex items-center justify-center rounded-full ${isTodayDate ? 'bg-indigo-600 text-white' : ''}`}>
                                                {format(day, 'd')}
                                            </span>
                                            {count === 10 && <div className="text-green-500"><CheckIcon className="w-4 h-4"/></div>}
                                        </div>
                                        <div className="w-full space-y-1">
                                            <div className="w-full bg-slate-100 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                                                <div className={`h-full ${getScoreColor(count)}`} style={{width: `${count * 10}%`}}></div>
                                            </div>
                                            <div className="text-[10px] font-bold text-slate-400 text-right">{count}/10</div>
                                        </div>
                                    </button>
                                );
                            })}
                        </div>
                    </>
                )}

                {calendarView === 'week' && (
                    <div className="overflow-x-auto">
                        <div className="min-w-[800px]">
                            <div className="grid grid-cols-[200px_repeat(7,1fr)] border-b border-slate-200 dark:border-slate-700">
                                <div className="p-4 font-bold text-slate-400 uppercase text-xs tracking-wider flex items-center bg-slate-50 dark:bg-slate-900/50">Habit (Default)</div>
                                {eachDayOfInterval({
                                    start: startOfWeek(currentDate),
                                    end: endOfWeek(currentDate)
                                }).map(day => (
                                    <button 
                                        key={day.toString()} 
                                        onClick={() => onSelectDate(format(day, 'yyyy-MM-dd'))}
                                        className={`p-4 text-center border-l border-slate-100 dark:border-slate-800 hover:bg-slate-100 dark:hover:bg-slate-800/80 transition-colors group ${isToday(day) ? 'bg-indigo-50 dark:bg-indigo-900/20' : ''}`}
                                    >
                                        <div className="text-xs font-bold text-slate-500 uppercase group-hover:text-indigo-600 dark:group-hover:text-indigo-400">{format(day, 'EEE')}</div>
                                        <div className={`text-lg font-bold mt-1 group-hover:scale-110 transition-transform ${isToday(day) ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{format(day, 'd')}</div>
                                        <div className="text-[10px] text-slate-400 mt-1 opacity-0 group-hover:opacity-100">Edit</div>
                                    </button>
                                ))}
                            </div>

                            {habitNames.map((habit, hIdx) => (
                                <div key={`${hIdx}-${habit}`} className="grid grid-cols-[200px_repeat(7,1fr)] border-b border-slate-100 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                    <div className="p-4 flex items-center text-sm font-semibold text-slate-700 dark:text-slate-300 truncate border-r border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-800/20" title={habit}>
                                        {habit}
                                    </div>
                                    {eachDayOfInterval({
                                        start: startOfWeek(currentDate),
                                        end: endOfWeek(currentDate)
                                    }).map(day => {
                                        const dStr = format(day, 'yyyy-MM-dd');
                                        const checks = getDayChecks(dStr);
                                        const isChecked = checks[hIdx];
                                        const isDayToday = isToday(day);

                                        return (
                                            <div key={dStr} className={`p-4 border-l border-slate-100 dark:border-slate-800 flex items-center justify-center ${isDayToday ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}>
                                                <button
                                                    onClick={() => onToggleHabit(dStr, hIdx)}
                                                    disabled={!isDayToday}
                                                    className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all duration-200 
                                                        ${isChecked ? 'bg-indigo-500 text-white shadow-md scale-110' : 'bg-slate-100 dark:bg-slate-700 text-transparent hover:bg-slate-200 dark:hover:bg-slate-600'}
                                                        ${!isDayToday ? 'opacity-50 cursor-not-allowed' : ''}
                                                    `}
                                                >
                                                    <CheckIcon className="w-5 h-5"/>
                                                </button>
                                            </div>
                                        )
                                    })}
                                </div>
                            ))}

                            <div className="grid grid-cols-[200px_repeat(7,1fr)] bg-slate-50 dark:bg-slate-900/50 border-t border-slate-200 dark:border-slate-700">
                                <div className="p-4 font-bold text-xs text-slate-400 uppercase tracking-wider border-r border-slate-200 dark:border-slate-800 flex items-center">Daily Score</div>
                                {eachDayOfInterval({
                                    start: startOfWeek(currentDate),
                                    end: endOfWeek(currentDate)
                                }).map(day => {
                                    const dStr = format(day, 'yyyy-MM-dd');
                                    const count = getDayChecks(dStr).filter(Boolean).length;
                                    return (
                                        <div key={dStr} className="p-4 text-center border-l border-slate-200 dark:border-slate-800">
                                            <span className={`inline-block px-3 py-1 rounded-full text-xs font-bold text-white ${getPercentageColor(count * 10)}`}>{count}/10</span>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

const ReportsView: React.FC<{ logs: HabitLog, getDayChecks: (d: string) => boolean[], onSelectDate: (d: string) => void, habitNames: string[] }> = ({ logs, getDayChecks, onSelectDate, habitNames }) => {
    const [viewMode, setViewMode] = useState<'analytics' | 'history'>('analytics');

    // Stats for Analytics
    const { pieData, barData, totalDays, monthlyData } = useMemo(() => {
        const scoreDist = [0, 0, 0, 0]; // 0: Inactive, 1: Average, 2: Good, 3: Perfect
        const habitCounts = new Array(10).fill(0);
        let total = 0;
        const monthMap: Record<string, { total: number; count: number }> = {};

        Object.entries(logs).forEach(([dateStr, val]) => {
            const checks = val as boolean[]; // Explicit cast to handle unknown type inference
            if (!checks || checks.length === 0) return;
            total++;
            const score = checks.filter(Boolean).length;

            // Pie Distribution
            if (score === 10) scoreDist[3]++;
            else if (score >= 6) scoreDist[2]++;
            else if (score >= 1) scoreDist[1]++;
            else scoreDist[0]++;

            // Habit Bar Data
            checks.forEach((c, i) => {
                if (c) habitCounts[i]++;
            });

            // Monthly Trend - Use Sortable Key (YYYY-MM)
            const dateObj = parseISO(dateStr);
            const monthSortKey = format(dateObj, 'yyyy-MM'); // e.g. 2024-01

            if (!monthMap[monthSortKey]) monthMap[monthSortKey] = { total: 0, count: 0 };
            monthMap[monthSortKey].total += score;
            monthMap[monthSortKey].count += 1;
        });

        const pie = [
            { label: 'Perfect (10)', value: scoreDist[3], color: '#10b981' }, // Emerald
            { label: 'Good (6-9)', value: scoreDist[2], color: '#3b82f6' }, // Blue
            { label: 'Average (1-5)', value: scoreDist[1], color: '#f59e0b' }, // Amber
            { label: 'Inactive (0)', value: scoreDist[0], color: '#ef4444' }, // Red
        ].filter(d => d.value > 0);

        const bar = habitNames.map((name, i) => ({
            label: name,
            value: habitCounts[i],
            percentage: total > 0 ? Math.round((habitCounts[i] / total) * 100) : 0,
            color: VIBRANT_COLORS[i % VIBRANT_COLORS.length]
        })).sort((a, b) => b.value - a.value);

        const monthly = Object.entries(monthMap)
            .sort(([keyA], [keyB]) => keyA.localeCompare(keyB)) // Sort by YYYY-MM
            .map(([sortKey, data]) => {
                // Convert 2024-01 to "Jan 2024" for display
                const label = format(parse(sortKey, 'yyyy-MM', new Date()), 'MMM yyyy');
                return {
                    label,
                    value: Math.round((data.total / data.count) * 10) / 10, // Average score
                    color: '#6366f1'
                };
            })
            .slice(-12); // Last 12 months

        return { pieData: pie, barData: bar, totalDays: total, monthlyData: monthly };
    }, [logs, habitNames]);

    const sortedDates = Object.keys(logs || {}).sort().reverse();

    return (
        <div className="space-y-6 animate-fade-in pb-10" key={habitNames.join(',')}>
            <div className="flex items-center justify-between gap-4 mb-4">
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white">Reports & Analytics</h2>
                <div className="flex bg-slate-100 dark:bg-slate-800 p-1 rounded-lg">
                    <button
                        onClick={() => setViewMode('analytics')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${
                            viewMode === 'analytics' 
                            ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-sm' 
                            : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        Charts
                    </button>
                    <button
                        onClick={() => setViewMode('history')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-md transition-all ${
                            viewMode === 'history' 
                            ? 'bg-white dark:bg-slate-700 text-indigo-600 dark:text-indigo-400 shadow-sm' 
                            : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-200'
                        }`}
                    >
                        History
                    </button>
                </div>
            </div>

            {viewMode === 'analytics' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Pie Chart Card */}
                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                        <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                            <div className="p-1.5 bg-indigo-100 dark:bg-indigo-900/30 rounded-md text-indigo-600 dark:text-indigo-400"><PieChartIcon className="w-4 h-4"/></div>
                            Consistency Breakdown
                        </h3>
                        <DonutChart data={pieData} total={totalDays} />
                    </div>

                    {/* Bar Chart Card */}
                    <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                         <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                            <div className="p-1.5 bg-emerald-100 dark:bg-emerald-900/30 rounded-md text-emerald-600 dark:text-emerald-400"><ListIcon className="w-4 h-4"/></div>
                            Habit Performance
                        </h3>
                        <HorizontalBarChart data={barData} />
                    </div>

                    {/* Trend Graph Card */}
                    <div className="md:col-span-2 bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm p-6">
                         <h3 className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                            <div className="p-1.5 bg-purple-100 dark:bg-purple-900/30 rounded-md text-purple-600 dark:text-purple-400"><ChartBarIcon className="w-4 h-4"/></div>
                            Monthly Average Score
                        </h3>
                        {monthlyData.length > 0 ? (
                            <VerticalBarGraph data={monthlyData} />
                        ) : (
                            <div className="h-32 flex items-center justify-center text-slate-400 text-sm">Insufficient data for trends</div>
                        )}
                    </div>
                </div>
            )}

            {viewMode === 'history' && (
                <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
                    <div className="divide-y divide-slate-100 dark:divide-slate-700">
                    {sortedDates.length === 0 && (
                        <div className="p-12 text-center text-slate-500 dark:text-slate-400">
                            No data recorded yet.
                        </div>
                    )}
                    {sortedDates.map(date => {
                        const count = getDayChecks(date).filter(Boolean).length;
                        return (
                            <div key={date} onClick={() => onSelectDate(date)} className="p-4 sm:p-5 hover:bg-slate-50 dark:hover:bg-slate-700/50 cursor-pointer transition-colors flex items-center justify-between group">
                                <div className="flex items-center gap-4">
                                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-bold text-lg text-white shadow-sm ${getScoreColor(count)}`}>
                                        {count}
                                    </div>
                                    <div>
                                        <p className="font-bold text-slate-900 dark:text-white">{format(parseISO(date), 'MMMM do, yyyy')}</p>
                                        <p className="text-xs text-slate-500 dark:text-slate-400 font-medium uppercase tracking-wide">{format(parseISO(date), 'EEEE')}</p>
                                    </div>
                                </div>
                                <ChevronDownIcon className="w-5 h-5 text-slate-300 group-hover:text-indigo-500 -rotate-90 transition-colors" />
                            </div>
                        );
                    })}
                    </div>
                </div>
            )}
        </div>
    );
};

