    const [selectedDateStr, setSelectedDateStr] = useState<string | null>(null);
    const [showHabitModal, setShowHabitModal] = useState(false);

    const [habits, setHabits] = useLocalStorage<Habit[]>('htwth-habits', []);
    const [completions, setCompletions] = useLocalStorage<Completions>('htwth-habit-completions', {});

    // Create/Edit State
    const [newHabitTitle, setNewHabitTitle] = useState('');
    const [deleteModalState, setDeleteModalState] = useState<{isOpen: boolean, habitId: string | null}>({isOpen: false, habitId: null});

    const getDayChecks = (dateStr: string): boolean[] => {
        const dayData = completions[dateStr] || {};
        // Map current habits to boolean status. If habit doesn't exist in dayData, it's false.
        return habits.map(h => !!dayData[h.id]);
    };

    const getMonthColor = (monthIndex: number, count: number): string => {
        const palette = MONTH_PALETTES[monthIndex].styles;
        if (count === 0) return 'bg-slate-50 dark:bg-slate-800/50';
        const intensity = Math.min(Math.ceil(count / 2), 5); // 0-5 index
        return palette[intensity];
    };

    // --- Actions ---

    const handlePrev = () => {
        if (calendarView === 'month') {
            setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
        } else {
            setCurrentDate(new Date(currentDate.getFullYear() - 1, 0, 1));
        }
    };

    const handleNext = () => {
        if (calendarView === 'month') {
            setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
        } else {
            setCurrentDate(new Date(currentDate.getFullYear() + 1, 0, 1));
        }
    };

    const toggleHabit = (habitId: string, dateStr: string) => {
        setCompletions(prev => {
            const dayData = prev[dateStr] || {};
            const newVal = !dayData[habitId];
            return {
                ...prev,
                [dateStr]: {
                    ...dayData,
                    [habitId]: newVal
                }
            };
        });
    };

    const handleAddHabit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!newHabitTitle.trim()) return;
        const newHabit: Habit = {
            id: crypto.randomUUID(),
            title: newHabitTitle.trim(),
        };
        setHabits([...habits, newHabit]);
        setNewHabitTitle('');
        setShowHabitModal(false);
    };

    const handleDeleteHabit = () => {
        if (deleteModalState.habitId) {
            setHabits(prev => prev.filter(h => h.id !== deleteModalState.habitId));
            // Optional: Cleanup completions for this habit id
        }
        setDeleteModalState({isOpen: false, habitId: null});
    };

    const onSelectDate = (dStr: string) => {
        setSelectedDateStr(dStr);
    };

    // Calculate Stats
    const stats = useMemo(() => {
        let totalCompleted = 0;
        let currentStreak = 0;
        // Simple streak logic: check consecutive days backwards from today
        const today = new Date();
        // Check if today is completed (at least one habit)
        // This is a naive streak. Real apps track per habit. Let's track "Any habit done" streak.

        let d = new Date(today);
        let broken = false;

        // Loop back 365 days max
        for(let i=0; i<365; i++) {
            const dStr = formatDate(d);
            const dayChecks = getDayChecks(dStr);
            const anyDone = dayChecks.some(Boolean);

            if (anyDone) {
                currentStreak++;
            } else if (i === 0) {
                // If today is not done yet, don't break streak if yesterday was done
            } else {
                broken = true;
            }

            if (broken) break;
            d.setDate(d.getDate() - 1);
        }

        // Total completions count
        Object.values(completions).forEach(day => {
            Object.values(day).forEach(val => {
                if (val) totalCompleted++;
            });
        });

        return { totalCompleted, currentStreak };
    }, [completions, habits]);

    return (
        <div className="flex h-full w-full bg-slate-50 dark:bg-slate-900 overflow-hidden relative flex-col">
            <ConfirmationModal 
                isOpen={deleteModalState.isOpen}
                onClose={() => setDeleteModalState({isOpen: false, habitId: null})}
                onConfirm={handleDeleteHabit}
                title="Delete Habit"
                confirmText="Delete"
            >
                <p>Are you sure you want to delete this habit? History for this habit will be lost.</p>
            </ConfirmationModal>

            {/* Header */}
            <header className="p-4 sm:p-6 border-b border-slate-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md z-10 flex-shrink-0">
                <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
                    <div className="flex items-center gap-4 w-full md:w-auto">
                        <h1 className="text-2xl font-bold text-slate-900 dark:text-white flex items-center gap-2">
                            <span className="bg-emerald-100 dark:bg-emerald-900/30 text-emerald-600 dark:text-emerald-400 p-2 rounded-lg">
                                <ChartBarIcon className="w-6 h-6"/>
                            </span>
                            Consistency
                        </h1>
                        <div className="flex items-center gap-2 text-sm font-semibold px-3 py-1 bg-slate-100 dark:bg-slate-800 rounded-full text-slate-600 dark:text-slate-300">
                            <FireIcon className="w-4 h-4 text-orange-500" />
                            <span>{stats.currentStreak} Day Streak</span>
                        </div>
                    </div>

                    <div className="flex items-center gap-3 w-full md:w-auto justify-between md:justify-end">
                        <div className="flex items-center bg-slate-100 dark:bg-slate-800 rounded-lg p-1">
                            <button 
                                onClick={() => setCalendarView('month')}
                                className={`px-3 py-1.5 text-xs font-bold uppercase tracking-wide rounded-md transition-all ${calendarView === 'month' ? 'bg-white dark:bg-slate-700 shadow-sm text-slate-900 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                            >
                                Month
                            </button>
                            <button 
                                onClick={() => setCalendarView('year')}
                                className={`px-3 py-1.5 text-xs font-bold uppercase tracking-wide rounded-md transition-all ${calendarView === 'year' ? 'bg-white dark:bg-slate-700 shadow-sm text-slate-900 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                            >
                                Year
                            </button>
                        </div>

                        <div className="flex items-center gap-2">
                            <button onClick={handlePrev} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400">
                                <ChevronLeft className="w-5 h-5" />
                            </button>
                            <span className="text-lg font-bold w-32 text-center text-slate-800 dark:text-slate-100">
                                {calendarView === 'month' ? MONTH_NAMES[currentDate.getMonth()] : currentDate.getFullYear()}
                                {calendarView === 'month' && <span className="text-sm font-normal text-slate-500 ml-1">{currentDate.getFullYear()}</span>}
                            </span>
                            <button onClick={handleNext} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-400">
                                <ChevronRight className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                </div>
            </header>

            {/* Main Content */}
            <main className="flex-1 overflow-y-auto p-4 sm:p-6 bg-slate-50/50 dark:bg-slate-950/50">

                {/* Habits Management */}
                <div className="max-w-7xl mx-auto mb-8">
                    <div className="flex items-center justify-between mb-4">
                        <h2 className="text-lg font-bold text-slate-800 dark:text-slate-200">Habits to Track</h2>
                        <button onClick={() => setShowHabitModal(true)} className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-sm font-bold transition-colors shadow-sm">
                            <PlusIcon className="w-4 h-4"/> New Habit
                        </button>
                    </div>
                    <div className="flex flex-wrap gap-3">
                        {habits.map(habit => (
                            <div key={habit.id} className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-full shadow-sm group">
                                <span className="font-medium text-slate-700 dark:text-slate-200">{habit.title}</span>
                                <button onClick={() => setDeleteModalState({isOpen: true, habitId: habit.id})} className="text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all p-0.5">
                                    <XCircleIcon className="w-4 h-4"/>
                                </button>
                            </div>
                        ))}
                        {habits.length === 0 && (
                            <p className="text-sm text-slate-500 italic">No habits added. Create one to start tracking!</p>
                        )}
                    </div>
                </div>

                {/* Create Habit Modal - Simple Inline */}
                {showHabitModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm animate-fade-in p-4">
                        <form onSubmit={handleAddHabit} className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-2xl w-full max-w-sm animate-slide-up border border-slate-200 dark:border-slate-700">
                            <h3 className="text-xl font-bold mb-4 text-slate-900 dark:text-white">New Habit</h3>
                            <input 
                                type="text" 
                                value={newHabitTitle} 
                                onChange={e => setNewHabitTitle(e.target.value)} 
                                className="w-full modern-input mb-4" 
                                placeholder="e.g. Read 30 mins"
                                autoFocus
                            />
                            <div className="flex justify-end gap-3">
                                <button type="button" onClick={() => setShowHabitModal(false)} className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg">Cancel</button>
                                <button type="submit" className="px-4 py-2 text-sm font-bold text-white bg-indigo-600 hover:bg-indigo-700 rounded-lg shadow-md">Add Habit</button>
                            </div>
                        </form>
                    </div>
                )}

                {/* Day Detail Modal */}
                {selectedDateStr && (
                    <div className="fixed inset-0 z-40 flex items-center justify-center bg-black/60 backdrop-blur-sm animate-fade-in p-4" onClick={() => setSelectedDateStr(null)}>
                        <div className="bg-white dark:bg-slate-800 w-full max-w-md rounded-2xl shadow-2xl overflow-hidden animate-scale-in" onClick={e => e.stopPropagation()}>
                            <header className="p-5 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50 flex justify-between items-center">
                                <div>
                                    <h3 className="text-xl font-bold text-slate-900 dark:text-white">
                                        {new Date(selectedDateStr).toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
                                    </h3>
                                    <p className="text-sm text-slate-500">Daily Check-in</p>
                                </div>
                                <button onClick={() => setSelectedDateStr(null)} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-500">
                                    <XCircleIcon className="w-6 h-6"/>
                                </button>
                            </header>
                            <div className="p-6 space-y-3">
                                {habits.length > 0 ? habits.map(habit => {
                                    const isDone = (completions[selectedDateStr] || {})[habit.id];
                                    return (
                                        <button 
                                            key={habit.id}
                                            onClick={() => toggleHabit(habit.id, selectedDateStr)}
                                            className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all duration-200 ${isDone ? 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800' : 'bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:bg-slate-100 dark:hover:bg-slate-700'}`}
                                        >
                                            <span className={`font-semibold ${isDone ? 'text-green-700 dark:text-green-300' : 'text-slate-700 dark:text-slate-300'}`}>{habit.title}</span>
                                            <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${isDone ? 'bg-green-500 border-green-500 text-white' : 'border-slate-300 dark:border-slate-500'}`}>
                                                {isDone && <CheckCircleIcon className="w-4 h-4 text-white" />}
                                            </div>
                                        </button>
                                    )
                                }) : (
                                    <p className="text-center text-slate-500 py-4">No habits defined. Add one to start tracking!</p>
                                )}
                            </div>
                        </div>
                    </div>
                )}

                {/* Calendar Grid */}
                <div className="max-w-7xl mx-auto bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
                    {calendarView === 'month' && (
                        <div className="p-6">
                            <div className="grid grid-cols-7 mb-4">
                                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                                    <div key={day} className="text-center text-xs font-bold uppercase text-slate-400 tracking-wider py-2">
                                        {day}
                                    </div>
                                ))}
                            </div>
                            <div className="grid grid-cols-7 gap-2">
                                {(() => {
                                    const { daysInMonth, firstDay } = getMonthData(currentDate.getFullYear(), currentDate.getMonth());
                                    const days = [];

                                    // Padding
                                    for (let i = 0; i < firstDay; i++) {
                                        days.push(<div key={`pad-${i}`} className="aspect-square"></div>);
                                    }

                                    // Days
                                    for (let d = 1; d <= daysInMonth; d++) {
                                        const date = new Date(currentDate.getFullYear(), currentDate.getMonth(), d);
                                        const dStr = formatDate(date);
                                        const checks = getDayChecks(dStr);
                                        const doneCount = checks.filter(Boolean).length;
                                        const totalHabits = habits.length;
                                        const isToday = dStr === formatDate(new Date());

                                        // Color logic
                                        let bgClass = 'bg-slate-50 dark:bg-slate-800/50 hover:bg-slate-100 dark:hover:bg-slate-700';
                                        let textClass = 'text-slate-700 dark:text-slate-300';

                                        if (totalHabits > 0 && doneCount > 0) {
                                            const ratio = doneCount / totalHabits;
                                            if (ratio === 1) {
                                                bgClass = 'bg-emerald-500 text-white shadow-md shadow-emerald-500/30';
                                                textClass = 'text-white font-bold';
                                            } else if (ratio >= 0.5) {
                                                bgClass = 'bg-emerald-300 dark:bg-emerald-600 text-emerald-900 dark:text-white';
                                            } else {
                                                bgClass = 'bg-emerald-100 dark:bg-emerald-900/30 text-emerald-700 dark:text-emerald-300';
                                            }
                                        }

                                        if (isToday) {
                                            bgClass += ' ring-2 ring-indigo-500 ring-offset-2 dark:ring-offset-slate-900';
                                        }

                                        days.push(
                                            <button 
                                                key={d} 
                                                onClick={() => onSelectDate(dStr)}
                                                className={`aspect-square rounded-xl flex flex-col items-center justify-center transition-all relative group ${bgClass}`}
                                            >
                                                <span className={`text-sm ${textClass}`}>{d}</span>
                                                {totalHabits > 0 && (
                                                    <div className="mt-1 flex gap-0.5">
                                                        {checks.slice(0, 3).map((c, i) => (
                                                            <div key={i} className={`w-1 h-1 rounded-full ${c ? 'bg-white/80' : 'bg-black/10 dark:bg-white/10'}`}></div>
                                                        ))}
                                                        {totalHabits > 3 && <span className="text-[6px] leading-none opacity-50">+</span>}
                                                    </div>
                                                )}
                                            </button>
                                        );
                                    }
                                    return days;
                                })()}
                            </div>
                        </div>
                    )}

                    {calendarView === 'year' && (
                        <div className="p-6 overflow-x-auto">
                            <div className="min-w-[700px] grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-8">
                                {Array.from({ length: 12 }).map((_, i) => {
                                    const monthDate = new Date(currentDate.getFullYear(), i, 1);
                                    const { daysInMonth, firstDay } = getMonthData(currentDate.getFullYear(), i);

                                    return (
                                        <div key={i} className="space-y-2">
                                            <h4 className={`text-sm font-bold ${MONTH_PALETTES[i].styles[3].replace('bg-', 'text-')} dark:${MONTH_PALETTES[i].styles[1].replace('bg-', 'text-')}`}>
                                                {MONTH_NAMES[i]}
                                            </h4>
                                            <div className="grid grid-cols-7 gap-1">
                                                {Array.from({ length: firstDay }).map((_, idx) => (
                                                    <div key={`pad-${idx}`} />
                                                ))}
                                                {Array.from({ length: daysInMonth }).map((_, dIdx) => {
                                                     const day = dIdx + 1;
                                                     const dStr = formatDate(new Date(currentDate.getFullYear(), i, day));
                                                     const checks = getDayChecks(dStr);
                                                     const count = checks.filter(Boolean).length;
                                                     const colorClass = getMonthColor(i, count);
                                                     const textColor = count > 5 ? 'text-white' : 'text-slate-600 dark:text-slate-300';

                                                     return (
                                                         <button
                                                            key={dStr}
                                                            onClick={() => onSelectDate(dStr)}
                                                            className={`w-full aspect-square rounded-sm hover:opacity-80 transition-opacity ${colorClass} flex items-center justify-center`}
                                                            title={`${dStr}: ${count}/${habits.length}`}
                                                         >
                                                            <span className={`text-[9px] sm:text-[10px] font-bold ${textColor}`}>
                                                                {day}
                                                            </span>
                                                         </button>
                                                     )
                                                })}
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
};

